import React, { useState } from 'react';
import ProductManager from '../components/Admin/ProductManager';
import AdminOrders from '../components/Admin/AdminOrders';
import InventoryView from '../components/Admin/InventoryView';
import { io } from 'socket.io-client';

const socket = io('http://localhost:5000');

const AdminDashboard = () => {
  const [tab, setTab] = useState('products');
  useEffect(() => {
    socket.on('lowStockAlert', (data) => {
      alert(`Low stock for ${data.name}: Only ${data.stock} left!`);
    });

    return () => socket.off('lowStockAlert');
  }, []);

  return (
    <div>
      <h1>Admin Dashboard</h1>
      <nav>
        <button onClick={() => setTab('products')}>Product Manager</button>
        <button onClick={() => setTab('orders')}>Orders Panel</button>
        <button onClick={() => setTab('inventory')}>Inventory View</button>
      </nav>
      <hr />
     {tab === 'products' && <ProductManager />}
      {tab === 'orders' && <AdminOrders />}
      {tab === 'inventory' && <InventoryView />}
    </div>
  );
};

export default AdminDashboard;
